import { Table, Thead, Tr, Th, Tbody, Td } from '@chakra-ui/react';
import React, {useState } from 'react';
import Axios from 'axios';

  function Application() {

  const [donnee_id, setDonnee_id] = useState([]);
  const [donnee_etablissementType, setDonnee_etablissementType] = useState([]);
  const [donnee_etablissement, setDonnee_etablissement] = useState([]);
  const [donnee_location, setDonnee_location] = useState([]);
  const [donnee_address, setDonnee_address] = useState([]);
  const [donnee_mail, setDonnee_mail] = useState([]);

    Axios.get("http://localhost:3001/api/utilisateur/${etablissement}").then((res) => {

      setDonnee_id(res.data.id)
      setDonnee_etablissementType(res.data.etablissementType)
      setDonnee_etablissement(res.data.etablissement)
      setDonnee_location(res.data.location)
      setDonnee_address(res.data.address)
      setDonnee_mail(res.data.mail)
 })

  return (
  <Table>
   <Thead>
    <Tr>
      <Th>id</Th>
      <Th>etablissement_type</Th>
      <Th>etablissement</Th>
      <Th>location</Th>
      <Th>address</Th>
      <Th>mail</Th>
    </Tr>
   </Thead>

   <Tbody>
    <Tr>
     <Td>{donnee_id.id}</Td>
     <Td>{donnee_etablissementType}</Td>
     <Td>{donnee_etablissement}</Td>
     <Td>{donnee_location}</Td>
     <Td>{donnee_address}</Td>
     <Td>{donnee_mail}</Td>
    </Tr>
   </Tbody>
  </Table>

  );
}

export default Application;
